Model as discriminated union:

interface RecommendedStdioServer { transport: 'stdio'; command: string; args?: string[] }
interface RecommendedHttpServer { transport: 'http' | 'sse'; url: string }
type RecommendedMcpServerTransport = RecommendedStdioServer | RecommendedHttpServer
type RecommendedMcpServer = { id: string; name: string; description: string; category: RecommendedCategory; official?: boolean } & RecommendedMcpServerTransport

